function generateWeakToken() {
  return Math.random().toString(36).substring(2, 15); // Predictable!
}

// SECURE: Generate cryptographically secure session token
function generateSessionToken() {
  return crypto.randomBytes(32).toString('hex'); // 64 hex characters = 256 bits
}

// SECURE: Generate password reset token with expiration
function generatePasswordResetToken() {
  const token = crypto.randomBytes(32).toString('base64url'); // URL-safe base64
  const expiresAt = new Date(Date.now() + 3600000); // 1 hour from now

  return {
    token,
    expiresAt,
    hash: crypto.createHash('sha256').update(token).digest('hex') // Store hash in DB
  };
}

