package com.example.security;

import java.security.SecureRandom;
import java.security.NoSuchAlgorithmException;
import java.util.Base64;
import java.time.Instant;
import java.time.temporal.ChronoUnit;
import org.springframework.stereotype.Service;
import org.springframework.security.crypto.codec.Hex;
import java.security.MessageDigest;

@Service
public class SecureTokenService {

    private static final SecureRandom secureRandom;
    private static final Base64.Encoder base64Encoder = Base64.getUrlEncoder().withoutPadding();

    static {
        try {
            // Use NativePRNGNonBlocking or SHA1PRNG depending on platform
            secureRandom = SecureRandom.getInstanceStrong();
        } catch (NoSuchAlgorithmException e) {
            throw new RuntimeException("Failed to initialize SecureRandom", e);
        }
    }

    // VULNERABLE CODE - DO NOT USE
    public String generateWeakToken() {
        java.util.Random weakRandom = new java.util.Random();
        return Long.toHexString(weakRandom.nextLong()); // Predictable!
    }

    // SECURE: Generate session token
    public String generateSessionToken() {
        byte[] randomBytes = new byte[32]; // 256 bits
        secureRandom.nextBytes(randomBytes);
        return base64Encoder.encodeToString(randomBytes);
    }

    // SECURE: Generate password reset token
    public PasswordResetToken generatePasswordResetToken() {
        byte[] randomBytes = new byte[32];
        secureRandom.nextBytes(randomBytes);
        String token = base64Encoder.encodeToString(randomBytes);

        // Hash token before storing in database
        String tokenHash = hashToken(token);

        Instant expiresAt = Instant.now().plus(1, ChronoUnit.HOURS);

        return new PasswordResetToken(token, tokenHash, expiresAt);
    }

    // Hash token using SHA-256
    private String hashToken(String token) {
        try {
            MessageDigest digest = MessageDigest.getInstance("SHA-256");
            byte[] hash = digest.digest(token.getBytes("UTF-8"));
            return new String(Hex.encode(hash));
        } catch (Exception e) {
            throw new RuntimeException("Failed to hash token", e);
        }
    }

    // SECURE: Generate API key with prefix
    public String generateAPIKey() {
        byte[] randomBytes = new byte[24];
        secureRandom.nextBytes(randomBytes);
        String randomPart = base64Encoder.encodeToString(randomBytes);
        return "sk_" + randomPart;
    }

    // SECURE: Generate CSRF token
    public String generateCSRFToken() {
        byte[] randomBytes = new byte[16]; // 128 bits sufficient for CSRF
        secureRandom.nextBytes(randomBytes);
        return base64Encoder.encodeToString(randomBytes);
    }

    // Inner class for password reset token
    public static class PasswordResetToken {
        private final String token;
        private final String tokenHash;
        private final Instant expiresAt;

        public PasswordResetToken(String token, String tokenHash, Instant expiresAt) {
            this.token = token;
            this.tokenHash = tokenHash;
            this.expiresAt = expiresAt;
        }

        public String getToken() { return token; }
        public String getTokenHash() { return tokenHash; }
        public Instant getExpiresAt() { return expiresAt; }
    }
}

// Controller example
@RestController
@RequestMapping("/api")
public class PasswordResetController {

    @Autowired
    private SecureTokenService tokenService;

    @Autowired
    private UserRepository userRepository;

    @Autowired
    private PasswordResetRepository resetRepository;

    @PostMapping("/password-reset")
    public ResponseEntity<?> requestPasswordReset(@RequestBody ResetRequest request) {
        User user = userRepository.findByEmail(request.getEmail());

        if (user == null) {
            // Prevent user enumeration - return generic message
            return ResponseEntity.ok(
                Map.of("message", "If account exists, reset email sent")
            );
        }

        // Generate secure token
        PasswordResetToken resetToken = tokenService.generatePasswordResetToken();

        // Save hashed token to database (NEVER store plaintext)
        PasswordResetEntity entity = new PasswordResetEntity();
        entity.setUserId(user.getId());
        entity.setTokenHash(resetToken.getTokenHash());
        entity.setExpiresAt(resetToken.getExpiresAt());
        entity.setUsed(false);
        resetRepository.save(entity);

        // Send email with token
        emailService.sendPasswordResetEmail(
            user.getEmail(),
            "https://example.com/reset-password?token=" + resetToken.getToken()
        );

        return ResponseEntity.ok(
            Map.of("message", "If account exists, reset email sent")
        );
    }
}
